 const property=propertyProgress?.item?.data||{},bank=bankProgress?.item?.data||{},missing=[];recordedGaps.forEach(record=>missing.push({text:record.item?.task||record.item?.notes||'Recorded information gap',target:'ciCategoryGaps',priority:normalise(record.item?.risk)==='high'?100:75}));
