 const supportedFacts=facts.filter(fact=>fact.supported),datedTimeline=timeline.filter(record=>Boolean(record.item?.date)),evidenceCoverage=facts.length?Math.round(supportedFacts.length/facts.length*100):0,timelineCoverage=facts.length?Math.min(100,Math.round(datedTimeline.length/facts.length*100)):0,hasIntelligence=Boolean(facts.length||evidence.length||timeline.length||propertyProgress||bankProgress),issueScore=hasIntelligence?Math.max(0,100-issues.length*20):0,informationScore=hasIntelligence?Math.max(0,100-missing.length*15):0,coreFields=[activeCase?.name,activeCase?.case_type,activeCase?.court,activeCase?.case_number,activeCase?.stage].filter(Boolean).length,foundationCoverage=Math.round((coreFields+builderChecks.filter(Boolean).length)/10*100),overall=Math.round(evidenceCoverage*.3+timelineCoverage*.2+issueScore*.15+informationScore*.15+foundationCoverage*.2);
